// Validate required fields exist and are correct types
const required = ['visitor_id','trigger_type','pricing_tier_clicked','time_on_pricing','scroll_depth','ip_address'];
const item = $input.first().json;
for (const field of required) {
  if (!item[field]) throw new Error(`Missing required field: ${field}`);
}
// Reject bot traffic
if (item.user_agent && item.user_agent.includes('bot')) throw new Error('Bot traffic rejected');
return $input.all();

const visitor = $('Pricing Page Webhook').first().json;
const clearbit = $('Clearbit Reveal — IP to Company').first().json;
const apollo = $('Apollo.io — Find Decision Maker').first().json.people[0];

// Feature mapping logic
const FEATURE_MAP = {
  'industrial distribution': 'Dealer Portal management',
  'manufacturing': 'Dealer Portal management',
  'fashion': 'variant management and bulk catalogue upload',
  'apparel': 'variant management and bulk catalogue upload',
  'retail': 'unified order management across channels',
  'electronics': 'bundle pricing and warranty SKU management',
  'technology': 'headless commerce and API-first architecture',
  'food': 'expiry tracking and reorder automation',
  'health': 'subscription and replenishment workflows',
};

const industry = (clearbit.category?.industry || '').toLowerCase();
let hero_feature = 'workflow automation and ERP integration';
for (const [key, val] of Object.entries(FEATURE_MAP)) {
  if (industry.includes(key)) { hero_feature = val; break; }
}

// Company size band
const emp = clearbit.metrics?.employees || 0;
const size_band = emp > 200 ? 'Enterprise' : emp > 50 ? 'Mid-Market' : 'SME';

// UTM-tagged Calendly link
const tier = visitor.pricing_tier_clicked.toLowerCase();
const visit_type = visitor.visit_count > 1 ? 'return' : 'first';
const calendly = `https://calendly.com/sellerscommerce/demo?utm_source=pricing-workflow&utm_tier=${tier}&utm_visit=${visit_type}`;

return [{
  json: {
    first_name: apollo.first_name,
    company_name: clearbit.name,
    job_title: apollo.title,
    industry: clearbit.category?.industry || 'Unknown',
    company_size_band: size_band,
    pricing_tier_clicked: visitor.pricing_tier_clicked,
    trigger_type: visitor.trigger_type,
    visit_count: visitor.visit_count,
    visit_type: visit_type,
    hero_feature: hero_feature,
    calendly_link: calendly,
    email: apollo.email,
    linkedin_url: apollo.linkedin_url || null,
    _meta: {
      visitor_id: visitor.visitor_id,
      session_id: visitor.session_id,
      assembled_at: new Date().toISOString()
    }
  }
}];

